create procedure [dbo].[CREATE_B2CLA] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.B2CLA','U') IS NOT NULL DROP TABLE B2CLA CREATE TABLE B2CLA ( [Recipient State Code] varchar(2) , [Original Invoice Number] varchar(21) , [Original Invoice date] datetime, [Recipient Name] varchar(60) , [Revised Invoice Number] varchar(21) , [Revised Invoice date] datetime, [Total Invoice Value] decimal, [Place Of Supply] varchar(2) , [Provisional Assessment] varchar(1) , [E-Commerce GSTIN] varchar(1) , [Category] varchar(1) , [HSN/SAC of Supply] varchar(16) , [Total Taxable Value] decimal, [IGST Rate] decimal, [IGST Amount] decimal, [CGSTRate] decimal, [CGST Amount] decimal, [SGST Rate] decimal, [SGST Amount] decimal, [CESS Rate] decimal, [CESS Amount] decimal) Set @Tablename='B2CLA' Select @Tablename 